'    RETURNING person_id INTO l_new_id;',
'',
'    INSERT INTO Users (user_id, person_id, username, password, role)',
'    VALUES (user_seq.NEXTVAL, l_new_id, :P_USERNAME, :P_PASSWORD, ''Customer'');',
'END;'))
