,p_plug_name=>'My Bookings'
,p_static_id=>'my-bookings'
,p_region_template_options=>'#DEFAULT#:t-IRR-region--hideHeader js-addHiddenHeadingRoleDesc'
,p_escape_on_http_output=>'N'
,p_plug_template=>2100526641005906379
,p_plug_display_sequence=>10
,p_plug_item_display_point=>'ABOVE'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    ''BOOK-'' || b.booking_id as booking_ref,',
'    TO_CHAR(b.booking_date, ''DD-MON-YYYY'') as booked_on,',
'    b.booking_status,',
'    t.ticket_number,',
'    TO_CHAR(t.issue_date, ''DD-MON-YYYY'') as ticket_date,',
'    TO_CHAR(t.ticket_price, ''FM9,999,999'') as price_pkr,',
'    f.flight_no,',
unistr('    src.iata_code || '' \2192 '' || dst.iata_code as route,'),
'    src.city || '' ('' || src.iata_code || '')'' as from_city,',
'    dst.city || '' ('' || dst.iata_code || '')'' as to_city,',
'    TO_CHAR(fs.departure_time, ''DD-MON-YYYY'') as departure_date,',
'    TO_CHAR(fs.departure_time, ''HH24:MI'') as departure_time,',
'    TO_CHAR(fs.arrival_time, ''DD-MON-YYYY HH24:MI'') as arrival,',
'    p.first_name || '' '' || p.last_name as passenger_name,',
'    b.seat_number,',
'    INITCAP(b.travel_class) as travel_class,',
'    t.baggage_allowed_kg || '' kg'' as baggage_allowance,',
'    b.booking_id as hidden_booking_id,',
'    fs.schedule_id as hidden_schedule_id,',
'    CASE b.booking_status',
'        WHEN ''Confirmed'' THEN ''CONFIRMED''',
'        WHEN ''Pending'' THEN ''PENDING''',
'        WHEN ''Cancelled'' THEN ''CANCELLED''',
'        WHEN ''Completed'' THEN ''COMPLETED''',
'    END as status_badge',
'',
'FROM bookings b',
'JOIN tickets t ON b.booking_id = t.booking_id',
'JOIN users u ON b.user_id = u.user_id',
'JOIN passengers pas ON b.passenger_id = pas.passenger_id',
'JOIN people p ON pas.person_id = p.person_id',
'JOIN flight_schedule fs ON b.schedule_id = fs.schedule_id',
'JOIN flights f ON fs.flight_id = f.flight_id',
'JOIN airports src ON f.source_airport_id = src.airport_id',
'JOIN airports dst ON f.destination_airport_id = dst.airport_id',
'WHERE u.username = :APP_USER',
'ORDER BY b.booking_date DESC'))
,p_plug_source_type=>'NATIVE_IR'
,p_plug_query_headings_type=>'COLON_DELMITED_LIST'
